static inline void cuda_check(cudaError_t err, const char *where) {
    if (err != cudaSuccess) {
        throw std::string(where) + " -> " + cudaGetErrorString(err);
    }
}

#ifdef TIMING
static inline void add_elapsed_ms(const struct timeval &start, const struct timeval &end, float &accum) {
    struct timeval diff;
    tvsub(&end, &start, &diff);
    accum += diff.tv_sec * 1000.0f + (float)diff.tv_usec / 1000.0f;
}
#endif

static inline void memcpy_h2d(void *dst, const void *src, size_t size) {
#ifdef TIMING
    struct timeval s, e;
    gettimeofday(&s, NULL);
#endif
    cuda_check(cudaMemcpy(dst, src, size, cudaMemcpyHostToDevice), "cudaMemcpy H2D");
#ifdef TIMING
    gettimeofday(&e, NULL);
    add_elapsed_ms(s, e, h2d_time);
#endif
}

static inline void memcpy_d2h(void *dst, const void *src, size_t size) {
#ifdef TIMING
    struct timeval s, e;
    gettimeofday(&s, NULL);
#endif
    cuda_check(cudaMemcpy(dst, src, size, cudaMemcpyDeviceToHost), "cudaMemcpy D2H");
#ifdef TIMING
    gettimeofday(&e, NULL);
    add_elapsed_ms(s, e, d2h_time);
#endif
}

template<typename datatype>
void compare_results(const datatype *cpu_results, const datatype *gpu_results, const int size) {
    char passed = true;
    for (int i = 0; i < size; i++) {
        if (cpu_results[i] != gpu_results[i]) {
            passed = false;
        }
    }
    if (passed) {
        std::cout << "--cambine:passed:-)" << std::endl;
    } else {
        std::cout << "--cambine: failed:-(" << std::endl;
    }
}

void _clCmdParams(int argc, char* argv[]) {
    for (int i = 0; i < argc; ++i) {
        if (argv[i] == NULL || argv[i][0] != '-') continue;
        switch (argv[i][1]) {
        case 'g':
            if (++i < argc) {
                sscanf(argv[i], "%u", &work_group_size);
            } else {
                std::cerr << "Could not read argument after option " << argv[i - 1] << std::endl;
                throw;
            }
            break;
        case 'd':
            if (++i < argc) {
                sscanf(argv[i], "%u", &device_id_inuse);
            } else {
                std::cerr << "Could not read argument after option " << argv[i - 1] << std::endl;
                throw;
            }
            break;
        case 'p':
            if (++i < argc) {
                sscanf(argv[i], "%u", &platform_id_inuse);
            } else {
                std::cerr << "Could not read argument after option " << argv[i - 1] << std::endl;
                throw;
            }
            break;
        default:
            ;
        }
    }
}

void _clInit() {
    int device_count = 0;
    cuda_check(cudaGetDeviceCount(&device_count), "cudaGetDeviceCount");
    printf("number of platforms:%d\n", 1);
    printf("vendor is %s\n", "NVIDIA Corporation");

    if (device_count <= 0) {
        throw std::string("InitCL()::Error: No devices found.");
    }

    std::cout << "device number: " << device_count << std::endl;

    if (device_id_inuse < 0 || device_id_inuse >= device_count) {
        throw std::string("InitCL()::Error: Invalid device id.");
    }

    cuda_check(cudaSetDevice(device_id_inuse), "cudaSetDevice");
    printf("Creating GPU Context\n");
}

void _clRelease() {
}

void run_bfs_cpu(int no_of_nodes, Node *h_graph_nodes, int edge_list_size,
                 int *h_graph_edges, char *h_graph_mask, char *h_updating_graph_mask,
                 char *h_graph_visited, int *h_cost_ref) {
    char stop;
    int k = 0;
    do {
        stop = false;
        for (int tid = 0; tid < no_of_nodes; tid++) {
            if (h_graph_mask[tid] == true) {
                h_graph_mask[tid] = false;
                for (int i = h_graph_nodes[tid].starting;
                     i < (h_graph_nodes[tid].no_of_edges + h_graph_nodes[tid].starting); i++) {
                    int id = h_graph_edges[i];
                    if (!h_graph_visited[id]) {
                        h_cost_ref[id] = h_cost_ref[tid] + 1;
                        h_updating_graph_mask[id] = true;
                    }
                }
            }
        }

        for (int tid = 0; tid < no_of_nodes; tid++) {
            if (h_updating_graph_mask[tid] == true) {
                h_graph_mask[tid] = true;
                h_graph_visited[tid] = true;
                stop = true;
                h_updating_graph_mask[tid] = false;
            }
        }
        k++;
    } while (stop);
}

void run_bfs_gpu(int no_of_nodes, Node *h_graph_nodes, int edge_list_size,
                 int *h_graph_edges, char *h_graph_mask, char *h_updating_graph_mask,
                 char *h_graph_visited, int *h_cost) {
    char h_over = false;
    Node *d_graph_nodes = NULL;
    int *d_graph_edges = NULL;
    char *d_graph_mask = NULL;
    char *d_updating_graph_mask = NULL;
    char *d_graph_visited = NULL;
    int *d_cost = NULL;
    char *d_over = NULL;

    try {
#ifdef TIMING
        gettimeofday(&tv_total_start, NULL);
#endif

        _clInit();

#ifdef TIMING
        gettimeofday(&tv_mem_alloc_start, NULL);
        tvsub(&tv_mem_alloc_start, &tv_total_start, &tv);
        init_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

        cuda_check(cudaMalloc((void**)&d_graph_nodes, no_of_nodes * sizeof(Node)), "cudaMalloc d_graph_nodes");
        cuda_check(cudaMalloc((void**)&d_graph_edges, edge_list_size * sizeof(int)), "cudaMalloc d_graph_edges");
        cuda_check(cudaMalloc((void**)&d_graph_mask, no_of_nodes * sizeof(char)), "cudaMalloc d_graph_mask");
        cuda_check(cudaMalloc((void**)&d_updating_graph_mask, no_of_nodes * sizeof(char)), "cudaMalloc d_updating_graph_mask");
        cuda_check(cudaMalloc((void**)&d_graph_visited, no_of_nodes * sizeof(char)), "cudaMalloc d_graph_visited");
        cuda_check(cudaMalloc((void**)&d_cost, no_of_nodes * sizeof(int)), "cudaMalloc d_cost");
        cuda_check(cudaMalloc((void**)&d_over, sizeof(char)), "cudaMalloc d_over");

#ifdef TIMING
        gettimeofday(&tv_mem_alloc_end, NULL);
        tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
        mem_alloc_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

        memcpy_h2d(d_graph_nodes, h_graph_nodes, no_of_nodes * sizeof(Node));
        memcpy_h2d(d_graph_edges, h_graph_edges, edge_list_size * sizeof(int));
        memcpy_h2d(d_graph_mask, h_graph_mask, no_of_nodes * sizeof(char));
        memcpy_h2d(d_updating_graph_mask, h_updating_graph_mask, no_of_nodes * sizeof(char));
        memcpy_h2d(d_graph_visited, h_graph_visited, no_of_nodes * sizeof(char));
        memcpy_h2d(d_cost, h_cost, no_of_nodes * sizeof(int));

#ifdef PROFILING
        timer kernel_timer;
        double kernel_time_local = 0.0;
        kernel_timer.reset();
        kernel_timer.start();
#endif

        do {
            h_over = false;
            memcpy_h2d(d_over, &h_over, sizeof(char));

            int threads = work_group_size;
            int blocks = (no_of_nodes + threads - 1) / threads;

#ifdef TIMING
            gettimeofday(&tv_kernel_start, NULL);
#endif

            BFS_1<<<blocks, threads>>>(d_graph_nodes,
                                       d_graph_edges,
                                       d_graph_mask,
                                       d_updating_graph_mask,
                                       d_graph_visited,
                                       d_cost,
                                       no_of_nodes);
            cuda_check(cudaGetLastError(), "BFS_1 launch");

            BFS_2<<<blocks, threads>>>(d_graph_mask,
                                       d_updating_graph_mask,
                                       d_graph_visited,
                                       d_over,
                                       no_of_nodes);
            cuda_check(cudaGetLastError(), "BFS_2 launch");

            memcpy_d2h(&h_over, d_over, sizeof(char));

#ifdef TIMING
            gettimeofday(&tv_kernel_end, NULL);
            add_elapsed_ms(tv_kernel_start, tv_kernel_end, kernel_time);
#endif
        } while (h_over);

        cuda_check(cudaDeviceSynchronize(), "cudaDeviceSynchronize");

#ifdef PROFILING
        kernel_timer.stop();
        kernel_time_local = kernel_timer.getTimeInSeconds();
#endif

        memcpy_d2h(h_cost, d_cost, no_of_nodes * sizeof(int));

#ifdef TIMING
        gettimeofday(&tv_close_start, NULL);
#endif

#ifdef PROFILING
        std::cout << "kernel time(s):" << kernel_time_local << std::endl;
#endif

        cudaFree(d_graph_nodes);
        cudaFree(d_graph_edges);
        cudaFree(d_graph_mask);
        cudaFree(d_updating_graph_mask);
        cudaFree(d_graph_visited);
        cudaFree(d_cost);
        cudaFree(d_over);
        _clRelease();
    } catch (std::string msg) {
        if (d_graph_nodes) cudaFree(d_graph_nodes);
        if (d_graph_edges) cudaFree(d_graph_edges);
        if (d_graph_mask) cudaFree(d_graph_mask);
        if (d_updating_graph_mask) cudaFree(d_updating_graph_mask);
        if (d_graph_visited) cudaFree(d_graph_visited);
        if (d_cost) cudaFree(d_cost);
        if (d_over) cudaFree(d_over);
        _clRelease();
        std::string e_str = "in run_transpose_gpu -> ";
        e_str += msg;
        throw(e_str);
    }

#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif

    return;
}

void Usage(int argc, char**argv) {
    fprintf(stderr, "Usage: %s <input_file> [-p platform] [-d device] [-t gpu(0)/cpu(1)]\n", argv[0]);
}

int main(int argc, char * argv[]) {
    int no_of_nodes = 0;
    int edge_list_size = 0;
    FILE *fp = NULL;
    Node* h_graph_nodes = NULL;
    char *h_graph_mask = NULL, *h_updating_graph_mask = NULL, *h_graph_visited = NULL;
    int *h_graph_edges = NULL;
    int *h_cost = NULL;
    int *h_cost_ref = NULL;

    try {
        char *input_f;
        if (argc < 2) {
            Usage(argc, argv);
            exit(0);
        }

        _clCmdParams(argc, argv);
        input_f = argv[1];
        printf("Reading File\n");

        fp = fopen(input_f, "r");
        if (!fp) {
            printf("Error Reading graph file\n");
            return 0;
        }

        int source = 0;

        fscanf(fp, "%d", &no_of_nodes);

        int num_of_blocks = 1;
        int num_of_threads_per_block = no_of_nodes;

        if (no_of_nodes > MAX_THREADS_PER_BLOCK) {
            num_of_blocks = (int)ceil(no_of_nodes / (double)MAX_THREADS_PER_BLOCK);
            num_of_threads_per_block = MAX_THREADS_PER_BLOCK;
        }
        (void)num_of_blocks;
        work_group_size = num_of_threads_per_block;

        h_graph_nodes = (Node*) malloc(sizeof(Node) * no_of_nodes);
        h_graph_mask = (char*) malloc(sizeof(char) * no_of_nodes);
        h_updating_graph_mask = (char*) malloc(sizeof(char) * no_of_nodes);
        h_graph_visited = (char*) malloc(sizeof(char) * no_of_nodes);

        int start, edgeno;

        for (int i = 0; i < no_of_nodes; i++) {
            fscanf(fp, "%d %d", &start, &edgeno);
            h_graph_nodes[i].starting = start;
            h_graph_nodes[i].no_of_edges = edgeno;
            h_graph_mask[i] = false;
            h_updating_graph_mask[i] = false;
            h_graph_visited[i] = false;
        }

        fscanf(fp, "%d", &source);
        source = 0;

        h_graph_mask[source] = true;
        h_graph_visited[source] = true;
        fscanf(fp, "%d", &edge_list_size);
        int id, cost;
        h_graph_edges = (int*) malloc(sizeof(int) * edge_list_size);
        for (int i = 0; i < edge_list_size; i++) {
            fscanf(fp, "%d", &id);
            fscanf(fp, "%d", &cost);
            h_graph_edges[i] = id;
        }

        if (fp)
            fclose(fp);
        fp = NULL;

        h_cost = (int*) malloc(sizeof(int) * no_of_nodes);
        h_cost_ref = (int*) malloc(sizeof(int) * no_of_nodes);
        for (int i = 0; i < no_of_nodes; i++) {
            h_cost[i] = -1;
            h_cost_ref[i] = -1;
        }
        h_cost[source] = 0;
        h_cost_ref[source] = 0;

        run_bfs_gpu(no_of_nodes, h_graph_nodes, edge_list_size, h_graph_edges,
                    h_graph_mask, h_updating_graph_mask, h_graph_visited, h_cost);

        for (int i = 0; i < no_of_nodes; i++) {
            h_graph_mask[i] = false;
            h_updating_graph_mask[i] = false;
            h_graph_visited[i] = false;
        }

        source = 0;
        h_graph_mask[source] = true;
        h_graph_visited[source] = true;
        run_bfs_cpu(no_of_nodes, h_graph_nodes, edge_list_size, h_graph_edges,
                    h_graph_mask, h_updating_graph_mask, h_graph_visited, h_cost_ref);

        compare_results<int>(h_cost_ref, h_cost, no_of_nodes);

        free(h_graph_nodes);
        free(h_graph_mask);
        free(h_updating_graph_mask);
        free(h_graph_visited);
        free(h_graph_edges);
        free(h_cost);
        free(h_cost_ref);
    } catch (std::string msg) {
        std::cout << "--cambine: exception in main ->" << msg << std::endl;
        if (fp) fclose(fp);
        free(h_graph_nodes);
        free(h_graph_mask);
        free(h_updating_graph_mask);
        free(h_graph_visited);
        free(h_graph_edges);
        free(h_cost);
        free(h_cost_ref);
    }

    return 0;
}

