class timer {
public:
    timer(const char *name = 0);
    timer(const char *name, std::ostream &write_on_exit);
    ~timer();

    void start(), stop();
    void reset();
    std::ostream &print(std::ostream &);
    double getTimeInSeconds();

private:
    double total_time;
    unsigned long long count;
    const char *const name;
