    std::chrono::high_resolution_clock::time_point start_time;
};

std::ostream &operator << (std::ostream &, class timer &);

timer::timer(const char *name)
    : total_time(0.0), count(0), name(name), write_on_exit(0) {
}

timer::timer(const char *name, std::ostream &write_on_exit)
    : total_time(0.0), count(0), name(name), write_on_exit(&write_on_exit) {
}

timer::~timer() {
    if (write_on_exit != 0) {
        print(*write_on_exit);
    }
}

void timer::start() {
    start_time = std::chrono::high_resolution_clock::now();
}

void timer::stop() {
    std::chrono::high_resolution_clock::time_point end_time =
        std::chrono::high_resolution_clock::now();
    total_time += std::chrono::duration<double>(end_time - start_time).count();
    ++count;
}

void timer::reset() {
    total_time = 0.0;
    count = 0;
}

std::ostream &timer::print(std::ostream &str) {
    str << std::left << std::setw(25) << (name != 0 ? name : "timer") << ": " << std::right;
    if (count > 0) {
        str << "avg = " << (total_time / static_cast<double>(count))
            << "  s, total = " << total_time
            << "  s, count = " << count << '\n';
    } else {
        str << "not used\n";
    }
    return str;
}

std::ostream &operator << (std::ostream &str, class timer &timer_obj) {
    return timer_obj.print(str);
}

double timer::getTimeInSeconds() {
    return total_time;
}
